/**
 * Custom theme definitions for T3 Code.
 *
 * Each theme declares semantic color tokens, font family, and font size.
 * The web app applies these as CSS custom properties on `<html>` so that
 * Tailwind utility classes (`bg-background`, `text-foreground`, etc.) pick
 * them up automatically.
 */

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface ThemeColors {
  background: string;
  foreground: string;
  accent: string;
  sidebar: string;
  editor: string;
  terminal: string;
  statusBar: string;
}

export interface Theme {
  id: string;
  name: string;
  colors: ThemeColors;
  fontFamily: string;
  fontSize: number;
}

// ---------------------------------------------------------------------------
// Built-in themes
// ---------------------------------------------------------------------------

const DEFAULT_FONT_FAMILY =
  '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif';

const t3Dark: Theme = {
  id: "t3-dark",
  name: "T3 Dark",
  colors: {
    background: "oklch(0.145 0.000 0)",
    foreground: "oklch(0.922 0.000 0)",
    accent: "oklch(0.588 0.217 264)",
    sidebar: "oklch(0.130 0.000 0)",
    editor: "oklch(0.145 0.000 0)",
    terminal: "oklch(0.115 0.000 0)",
    statusBar: "oklch(0.160 0.000 0)",
  },
  fontFamily: DEFAULT_FONT_FAMILY,
  fontSize: 14,
};

const t3Light: Theme = {
  id: "t3-light",
  name: "T3 Light",
  colors: {
    background: "oklch(1.000 0.000 0)",
    foreground: "oklch(0.269 0.000 0)",
    accent: "oklch(0.488 0.217 264)",
    sidebar: "oklch(0.975 0.000 0)",
    editor: "oklch(1.000 0.000 0)",
    terminal: "oklch(0.970 0.000 0)",
    statusBar: "oklch(0.960 0.000 0)",
  },
  fontFamily: DEFAULT_FONT_FAMILY,
  fontSize: 14,
};

const t3Midnight: Theme = {
  id: "t3-midnight",
  name: "T3 Midnight",
  colors: {
    background: "oklch(0.160 0.025 270)",
    foreground: "oklch(0.890 0.010 270)",
    accent: "oklch(0.650 0.250 270)",
    sidebar: "oklch(0.140 0.030 270)",
    editor: "oklch(0.160 0.025 270)",
    terminal: "oklch(0.120 0.030 270)",
    statusBar: "oklch(0.180 0.020 270)",
  },
  fontFamily: DEFAULT_FONT_FAMILY,
  fontSize: 14,
};

// ---------------------------------------------------------------------------
// Registry
// ---------------------------------------------------------------------------

const BUILT_IN_THEMES: readonly Theme[] = [t3Dark, t3Light, t3Midnight];

const themeMap = new Map<string, Theme>(BUILT_IN_THEMES.map((t) => [t.id, t]));

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/**
 * Return a theme by `id`. Falls back to `"t3-dark"` when the id is unknown.
 */
export function getTheme(id: string): Theme {
  return themeMap.get(id) ?? t3Dark;
}

/**
 * Return every registered theme (built-in).
 */
export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

