import type { Theme } from "@t3tools/shared/themes";

import { useTheme } from "../hooks/useTheme";

// ---------------------------------------------------------------------------
// Swatch — a small preview of a theme's key colors
// ---------------------------------------------------------------------------

function ThemeSwatch({ theme }: { theme: Theme }) {
  const { background, foreground, accent, sidebar } = theme.colors;
  return (
    <div
      className="flex h-8 w-14 shrink-0 overflow-hidden rounded-md border border-border"
      aria-hidden="true"
    >
      {/* sidebar sliver */}
      <div className="w-3" style={{ backgroundColor: sidebar }} />
      {/* main area */}
      <div className="flex flex-1 flex-col items-center justify-center gap-0.5" style={{ backgroundColor: background }}>
        <div className="h-1 w-5 rounded-full" style={{ backgroundColor: foreground, opacity: 0.6 }} />
        <div className="h-1 w-4 rounded-full" style={{ backgroundColor: accent }} />
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// ThemeSelector
// ---------------------------------------------------------------------------

export function ThemeSelector() {
  const { customTheme, setCustomTheme, availableThemes } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Custom theme">
      {availableThemes.map((t) => {
        const selected = customTheme.id === t.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full items-center gap-3 rounded-lg border px-3 py-2 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setCustomTheme(t.id)}
          >
            <ThemeSwatch theme={t} />
            <span className="flex flex-1 flex-col">
              <span className="text-sm font-medium">{t.name}</span>
              <span className="text-xs">
                {t.fontFamily.split(",")[0]?.replaceAll('"', "").trim() ?? "System"} &middot;{" "}
                {String(t.fontSize)}px
              </span>
            </span>
            {selected ? (
              <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Active
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}
